2256 |     // --- CLIENT SIDE PATCH ENGINE (Smart Line-Matcher) ---
2257 |     function applyLocalPatch(content, ops) {
2258 |         let lines = content.split('\n');
2259 |         let logs = [];
2260 |         let success = true;
2261 | 
2262 |         if (typeof ops === 'string') {
2263 |             try { ops = JSON.parse(ops); } catch(e) { return { content, success: false, logs: ["Invalid JSON"]}; }
2264 |         }
2265 | 
2266 |         ops.forEach(op => {
2267 |             if (op.action === 'comment') return;
2268 |             if (op.action === 'create_file') { lines = op.content.split('\n'); logs.push('Created file'); return; }
2269 |             
2270 |             if (op.action === 'replace_block') {
2271 |                 // Strategy 1: Exact String Match (Fastest)
2272 |                 const currentStr = lines.join('\n');
2273 |                 if (currentStr.includes(op.find_block)) {
2274 |                     lines = currentStr.replace(op.find_block, op.replace_with).split('\n');
2275 |                     logs.push('Exact match applied');
2276 |                     return;
2277 |                 }
2278 | 
2279 |                 // Strategy 2: Line-by-Line Fuzzy Match (Whitespace Agnostic)
2280 |                 const searchLines = op.find_block.split('\n').map(l => l.trim()).filter(l => l !== '');
2281 |                 if (searchLines.length === 0) return;
2282 | 
2283 |                 let matchStart = -1;
2284 |                 let matchEnd = -1;
2285 | 
2286 |                 // Scan file lines
2287 |                 for (let i = 0; i < lines.length; i++) {
2288 |                     // If first line matches (ignoring whitespace)
2289 |                     if (lines[i].trim() === searchLines[0]) {
2290 |                         // Check subsequent lines
2291 |                         let allMatch = true;
2292 |                         let fileOffset = 0;
2293 |                         let searchOffset = 1;
2294 |                         
2295 |                         while (searchOffset < searchLines.length) {
2296 |                             if (i + fileOffset + 1 >= lines.length) { allMatch = false; break; }
2297 |                             const nextFile = lines[i + fileOffset + 1].trim();
2298 |                             // Skip empty lines in file if they aren't in search block
2299 |                             if (nextFile === '') {
2300 |                                 fileOffset++;
2301 |                                 continue;
2302 |                             }
2303 |                             if (nextFile !== searchLines[searchOffset]) {
2304 |                                 allMatch = false;
2305 |                                 break;
2306 |                             }
2307 |                             fileOffset++;
2308 |                             searchOffset++;
2309 |                         }
2310 | 
2311 |                         if (allMatch) {
2312 |                             matchStart = i;
2313 |                             matchEnd = i + fileOffset;
2314 |                             break;
2315 |                         }
2316 |                     }
2317 |                 }
2318 | 
2319 |                 if (matchStart !== -1) {
2320 |                     // Replace the range of lines
2321 |                     const replacement = op.replace_with.split('\n');
2322 |                     lines.splice(matchStart, (matchEnd - matchStart) + 1, ...replacement);
2323 |                     logs.push(`Fuzzy match applied (Lines ${matchStart+1}-${matchEnd+1})`);
2324 |                 } else {
2325 |                     success = false;
2326 |                     logs.push(`Failed to find block: "${op.find_block.substring(0, 30)}..."`);
2327 |                     console.warn("Patch Mismatch. File has:", content.substring(0, 200), "... vs Search:", op.find_block);
2328 |                 }
2329 |             }
2330 |         });
2331 |         return { content: lines.join('\n'), success, logs };
2332 |     }
