2357 |                         error: err 
2358 |                     })
2359 |                 });
2360 |                 const data = await res.json();
2361 |                 const ops = data.operations;
2362 | 
2363 |                 if (!ops || ops === "[]") throw new Error("AI could not generate a fix.");
2364 | 
2365 |                 // 2. Apply Patch Locally
2366 |                 const patchResult = applyLocalPatch(currentCode, ops);
2367 |                 if (!patchResult.success) throw new Error("Generated patch did not match code.");
2368 | 
2369 |                 currentCode = patchResult.content;
2370 |                 document.getElementById('ef-code').value = currentCode; // Update UI
