2384 |                     currentErrors = scanData.errors;
2385 |                     if (confirm(`Fix applied, but ${currentErrors.length} errors remain. Continue fixing?`)) {
2386 |                         // Recursively fix the *new* first error (since layout changed)
2387 |                         return await fixNext(0);
2388 |                     } else {
2389 |                         return false;
2390 |                     }
2391 |                 }
2392 | 
2393 |             } catch (e) {
2394 |                 if (confirm(`Auto-Fix Failed: ${e.message}\n\nTry again?`)) {
2395 |                     return await fixNext(index);
2396 |                 } else {
2397 |                     return false;
2398 |                 }
2399 |             }
2400 |         }
2401 | 
2402 |         return await fixNext(0);
