6530 |         const toast = document.createElement('div');
6531 |         toast.innerText = "Parsing " + file.name + "...";
6532 |         toast.style.cssText = "position:fixed; bottom:100px; left:50%; transform:translateX(-50%); background:#333; color:white; padding:10px 20px; border-radius:30px; z-index:9999;";
6533 |         document.body.appendChild(toast);
6534 | 
6535 |         pendingImportFiles = [];
6536 | 
6537 |         try {
6538 |             if (file.name.endsWith('.zip')) {
6539 |                 const zip = await JSZip.loadAsync(file);
6540 |                 const promises = [];
6541 |                 zip.forEach((relativePath, zipEntry) => {
6542 |                     if (!zipEntry.dir) {
6543 |                         promises.push(zipEntry.async("string").then(content => {
6544 |                             pendingImportFiles.push({ path: relativePath, content: content });
6545 |                         }));
6546 |                     }
6547 |                 });
6548 |                 await Promise.all(promises);
6549 |             } 
6550 |             else if (file.name.endsWith('.txt')) {
6551 |                 const text = await file.text();
6552 |                 // Parse "FILE: path\nContent" format
6553 |                 // Split by "\n\nFILE: " to handle multiple files, assuming double newline separator from export
6554 |                 const chunks = text.split(/\n\nFILE: /g);
6555 |                 
6556 |                 chunks.forEach((chunk, index) => {
6557 |                     // Handle first chunk edge case if it starts with "FILE: "
6558 |                     let cleanChunk = chunk;
6559 |                     if (index === 0 && chunk.startsWith("FILE: ")) cleanChunk = chunk.substring(6);
6560 |                     
6561 |                     const firstLineEnd = cleanChunk.indexOf('\n');
6562 |                     if (firstLineEnd !== -1) {
6563 |                         const path = cleanChunk.substring(0, firstLineEnd).trim();
6564 |                         const content = cleanChunk.substring(firstLineEnd + 1);
6565 |                         if (path) pendingImportFiles.push({ path, content });
6566 |                     }
