7040 |         const idsToDelete = checkboxes.map(cb => cb.value);
7041 |         
7042 |         // Find the oldest record among the selection to determine rollback target
7043 |         // dbHistory is sorted newest -> oldest
7044 |         let oldestSelectedIndex = -1;
7045 |         checkboxes.forEach(cb => {
7046 |             const idx = dbHistory.findIndex(h => String(h.id) === String(cb.value));
7047 |             if (idx > oldestSelectedIndex) oldestSelectedIndex = idx;
7048 |         });
7049 | 
7050 |         // The target is the first record older than our selection that isn't also being deleted
7051 |         let rollbackTarget = null;
7052 |         for (let i = oldestSelectedIndex + 1; i < dbHistory.length; i++) {
7053 |             if (!idsToDelete.includes(String(dbHistory[i].id))) {
7054 |                 rollbackTarget = dbHistory[i];
7055 |                 break;
7056 |             }
