5388 |     async function jumpToElement(selector, tabId, navIndex, loadMoreFn) {
5389 |         console.group(`[DeepJump] Target: ${selector} in ${tabId}`);
5390 |         
5391 |         const navItems = document.querySelectorAll('.nav-item');
5392 |         switchTab(tabId, navItems[navIndex]);
5393 | 
5394 |         const scrollContainer = document.querySelector('.main-view');
5395 |         let retryCount = 0;
5396 |         const MAX_RETRIES = 5;
5397 | 
5398 |         const attemptNavigation = async () => {
5399 |             const element = document.querySelector(selector);
5400 |             
5401 |             if (element) {
5402 |                 console.log("[DeepJump] Element found. Scrolling...");
5403 |                 
5404 |                 // Wait for any tab transition animations
5405 |                 await new Promise(r => setTimeout(r, 300));
5406 | 
5407 |                 let offsetTop = 0;
5408 |                 let curr = element;
5409 |                 while (curr && curr !== scrollContainer) {
5410 |                     offsetTop += curr.offsetTop;
5411 |                     curr = curr.offsetParent;
5412 |                 }
5413 | 
5414 |                 const targetScroll = offsetTop - (scrollContainer.clientHeight / 2) + (element.clientHeight / 2);
5415 |                 scrollContainer.scrollTo({ top: targetScroll, behavior: 'smooth' });
5416 | 
5417 |                 // Visual Highlight
5418 |                 element.style.transition = 'all 0.5s ease';
5419 |                 element.style.backgroundColor = 'rgba(59, 130, 246, 0.3)';
5420 |                 element.style.boxShadow = '0 0 30px rgba(59, 130, 246, 0.6)';
5421 |                 setTimeout(() => {
5422 |                     element.style.backgroundColor = '';
5423 |                     element.style.boxShadow = '';
5424 |                 }, 3000);
5425 |                 
5426 |                 console.groupEnd();
5427 |                 return true;
5428 |             }
5429 | 
5430 |             if (retryCount < MAX_RETRIES && loadMoreFn) {
5431 |                 console.log(`[DeepJump] Not found. Triggering loadMore (Attempt ${retryCount + 1})...`);
5432 |                 retryCount++;
5433 |                 showGlobalToast("ð Searching deeper...");
5434 |                 
5435 |                 await loadMoreFn(); 
5436 |                 await new Promise(r => setTimeout(r, 800)); // Wait for render
5437 |                 return attemptNavigation();
5438 |             }
5439 | 
5440 |             console.error("[DeepJump] Failed: Element not found after retries.");
5441 |             showGlobalToast("Entry not found in recent history.", true);
5442 |             console.groupEnd();
5443 |             return false;
5444 |         };
5445 | 
5446 |         setTimeout(attemptNavigation, 100);
5447 |     }
