7864 |     function extractTableNames(sql) {
7865 |         if (!sql) return [];
7866 |         const tables = [];
7867 |         const systemNoise = ['columns', 'tables', 'schemata', 'information_schema'];
7868 |         
7869 |         // Pattern 1: Standard FROM/JOIN (handles schema.table and "table")
7870 |         const fromRegex = /(?:FROM|JOIN)\s+(?:(?:"?\w+"?\.)?"?(\w+)"?)/gi;
7871 |         // Pattern 2: Metadata queries (WHERE table_name = '...')
7872 |         const metaRegex = /table_name\s*=\s*'([^']+)'/gi;
7873 | 
7874 |         let match;
7875 |         while ((match = fromRegex.exec(sql)) !== null) {
7876 |             const name = match[1];
7877 |             if (name && !tables.includes(name) && !systemNoise.includes(name.toLowerCase())) {
7878 |                 tables.push(name);
7879 |             }
7880 |         }
7881 |         
7882 |         while ((match = metaRegex.exec(sql)) !== null) {
7883 |             const name = match[1];
7884 |             if (name && !tables.includes(name) && !systemNoise.includes(name.toLowerCase())) {
7885 |                 tables.push(name);
7886 |             }
7887 |         }
7888 | 
7889 |         return tables;
7890 |     }
7891 | 
7892 |     function convertToCSV(resultObj) {
7893 |         const data = resultObj.data || [];
7894 |         if (!data.length) return '';
7895 |         
7896 |         const tables = extractTableNames(resultObj.sql);
7897 |         const metaHeader = tables.length > 0 ? `# Source Tables: ${tables.join(', ')}\n# Export Date: ${new Date().toISOString()}\n` : '';
7898 | 
7899 |         const headers = Object.keys(data[0]);
7900 |         const rows = data.map(row => 
7901 |             headers.map(header => {
7902 |                 let cell = row[header] === null || row[header] === undefined ? '' : row[header];
7903 |                 if (typeof cell === 'object') cell = JSON.stringify(cell);
7904 |                 return '"' + String(cell).replace(/"/g, '""') + '"';
7905 |             }).join(',')
7906 |         );
7907 |         return metaHeader + [headers.join(','), ...rows].join('\n');
7908 |     }
