2052 |         stack.pop(); 
2053 |         const parts = relative.split('/');
2054 |         for (let i = 0; i < parts.length; i++) {
2055 |             if (parts[i] === '.') continue;
2056 |             if (parts[i] === '..') stack.pop();
2057 |             else stack.push(parts[i]);
2058 |         }
2059 |         return stack.join('/');
