2255 |     // --- CLIENT SIDE PATCH ENGINE (Smart Line-Matcher) ---
2256 |     function applyLocalPatch(content, ops) {
2257 |         let lines = content.split('\n');
2258 |         let logs = [];
2259 |         let success = true;
2260 | 
2261 |         if (typeof ops === 'string') {
2262 |             try { ops = JSON.parse(ops); } catch(e) { return { content, success: false, logs: ["Invalid JSON"]}; }
2263 |         }
2264 | 
2265 |         ops.forEach(op => {
2266 |             if (op.action === 'comment') return;
2267 |             if (op.action === 'create_file') { lines = op.content.split('\n'); logs.push('Created file'); return; }
2268 |             
2269 |             if (op.action === 'replace_block') {
2270 |                 // Strategy 1: Exact String Match (Fastest)
2271 |                 const currentStr = lines.join('\n');
2272 |                 if (currentStr.includes(op.find_block)) {
2273 |                     lines = currentStr.replace(op.find_block, op.replace_with).split('\n');
2274 |                     logs.push('Exact match applied');
2275 |                     return;
2276 |                 }
2277 | 
2278 |                 // Strategy 2: Line-by-Line Fuzzy Match (Whitespace Agnostic)
2279 |                 const searchLines = op.find_block.split('\n').map(l => l.trim()).filter(l => l !== '');
2280 |                 if (searchLines.length === 0) return;
2281 | 
2282 |                 let matchStart = -1;
2283 |                 let matchEnd = -1;
2284 | 
2285 |                 // Scan file lines
2286 |                 for (let i = 0; i < lines.length; i++) {
2287 |                     // If first line matches (ignoring whitespace)
2288 |                     if (lines[i].trim() === searchLines[0]) {
2289 |                         // Check subsequent lines
2290 |                         let allMatch = true;
2291 |                         let fileOffset = 0;
2292 |                         let searchOffset = 1;
2293 |                         
2294 |                         while (searchOffset < searchLines.length) {
2295 |                             if (i + fileOffset + 1 >= lines.length) { allMatch = false; break; }
2296 |                             const nextFile = lines[i + fileOffset + 1].trim();
2297 |                             // Skip empty lines in file if they aren't in search block
2298 |                             if (nextFile === '') {
2299 |                                 fileOffset++;
2300 |                                 continue;
2301 |                             }
2302 |                             if (nextFile !== searchLines[searchOffset]) {
2303 |                                 allMatch = false;
2304 |                                 break;
2305 |                             }
2306 |                             fileOffset++;
2307 |                             searchOffset++;
2308 |                         }
2309 | 
2310 |                         if (allMatch) {
2311 |                             matchStart = i;
2312 |                             matchEnd = i + fileOffset;
2313 |                             break;
2314 |                         }
2315 |                     }
2316 |                 }
2317 | 
2318 |                 if (matchStart !== -1) {
2319 |                     // Replace the range of lines
2320 |                     const replacement = op.replace_with.split('\n');
2321 |                     lines.splice(matchStart, (matchEnd - matchStart) + 1, ...replacement);
2322 |                     logs.push(`Fuzzy match applied (Lines ${matchStart+1}-${matchEnd+1})`);
2323 |                 } else {
2324 |                     success = false;
2325 |                     logs.push(`Failed to find block: "${op.find_block.substring(0, 30)}..."`);
2326 |                     console.warn("Patch Mismatch. File has:", content.substring(0, 200), "... vs Search:", op.find_block);
2327 |                 }
2328 |             }
2329 |         });
2330 |         return { content: lines.join('\n'), success, logs };
2331 |     }
