2335 |     async function runAutoFixLoop(name, code, errorList) {
2336 |         const status = document.getElementById('ef-status-msg');
2337 |         let currentCode = code;
2338 |         let currentErrors = errorList;
2339 | 
2340 |         // Fix one by one (recursive loop)
2341 |         async function fixNext(index) {
2342 |             if (index >= currentErrors.length) return true; // All initial errors processed
2343 | 
2344 |             const err = currentErrors[index];
2345 |             status.innerText = `ð§ Fixing Error ${index + 1}/${currentErrors.length} (Line ${err.line})...`;
2346 |             status.style.color = "#eab308"; // Dev yellow
2347 | 
2348 |             try {
2349 |                 // 1. Get Patch from AI
2350 |                 const res = await fetch(CONFIG.funcUrl, { 
2351 |                     method: 'POST', 
2352 |                     headers: {'Content-Type': 'application/json'},
2353 |                     body: apiBody({ 
2354 |                         action: 'propose_syntax_fix', 
2355 |                         code: currentCode, 
2356 |                         error: err 
2357 |                     })
2358 |                 });
2359 |                 const data = await res.json();
2360 |                 const ops = data.operations;
2361 | 
2362 |                 if (!ops || ops === "[]") throw new Error("AI could not generate a fix.");
2363 | 
2364 |                 // 2. Apply Patch Locally
2365 |                 const patchResult = applyLocalPatch(currentCode, ops);
2366 |                 if (!patchResult.success) throw new Error("Generated patch did not match code.");
2367 | 
2368 |                 currentCode = patchResult.content;
2369 |                 document.getElementById('ef-code').value = currentCode; // Update UI
2370 | 
2371 |                 // 3. Re-Validate
2372 |                 const scanRes = await fetch(CONFIG.funcUrl, { 
2373 |                     method: 'POST', headers: {'Content-Type': 'application/json'},
2374 |                     body: apiBody({ action: 'validate_syntax_deep', code_block: currentCode, file_path: 'index.ts' })
2375 |                 });
2376 |                 const scanData = await scanRes.json();
2377 | 
2378 |                 if (scanData.valid) {
2379 |                     status.innerText = "â Syntax Fixed!";
2380 |                     return true;
2381 |                 } else {
2382 |                     // If errors remain, update list and Prompt user
2383 |                     currentErrors = scanData.errors;
2384 |                     if (confirm(`Fix applied, but ${currentErrors.length} errors remain. Continue fixing?`)) {
2385 |                         // Recursively fix the *new* first error (since layout changed)
2386 |                         return await fixNext(0);
2387 |                     } else {
2388 |                         return false;
2389 |                     }
2390 |                 }
2391 | 
2392 |             } catch (e) {
2393 |                 if (confirm(`Auto-Fix Failed: ${e.message}\n\nTry again?`)) {
2394 |                     return await fixNext(index);
2395 |                 } else {
2396 |                     return false;
2397 |                 }
2398 |             }
2399 |         }
2400 | 
2401 |         return await fixNext(0);
2402 |     }
