7035 |     async function deleteSelectedHistory() {
7036 |         const checkboxes = Array.from(document.querySelectorAll('.history-check:checked'));
7037 |         if (!checkboxes.length) return;
7038 | 
7039 |         const idsToDelete = checkboxes.map(cb => cb.value);
7040 |         
7041 |         // Find the oldest record among the selection to determine rollback target
7042 |         // dbHistory is sorted newest -> oldest
7043 |         let oldestSelectedIndex = -1;
7044 |         checkboxes.forEach(cb => {
7045 |             const idx = dbHistory.findIndex(h => String(h.id) === String(cb.value));
7046 |             if (idx > oldestSelectedIndex) oldestSelectedIndex = idx;
7047 |         });
7048 | 
7049 |         // The target is the first record older than our selection that isn't also being deleted
7050 |         let rollbackTarget = null;
7051 |         for (let i = oldestSelectedIndex + 1; i < dbHistory.length; i++) {
7052 |             if (!idsToDelete.includes(String(dbHistory[i].id))) {
7053 |                 rollbackTarget = dbHistory[i];
7054 |                 break;
7055 |             }
7056 |         }
7057 | 
7058 |         let msg = `Delete ${checkboxes.length} selected records?`;
7059 |         if (rollbackTarget) {
7060 |             msg += `\n\nâ ï¸ This will ROLLBACK your GitHub repository to: "${rollbackTarget.title}"`;
7061 |         }
7062 | 
7063 |         if (!confirm(msg)) return;
7064 | 
7065 |         showGlobalToast("Batch Deleting & Rolling back...");
7066 | 
7067 |         // 1. Perform Rollback
7068 |         if (rollbackTarget) {
7069 |             await fetch(CONFIG.funcUrl, {
7070 |                 method: 'POST', headers: {'Content-Type': 'application/json'},
7071 |                 body: apiBody({ action: 'rollback', ref_sha: rollbackTarget.sha })
7072 |             });
7073 |         }
7074 | 
7075 |         // 2. Perform Batch Deletion
7076 |         await Promise.all(idsToDelete.map(id => 
7077 |             fetch(CONFIG.funcUrl, {
7078 |                 method: 'POST', headers: {'Content-Type': 'application/json'},
7079 |                 body: apiBody({ action: 'delete_history', id: id })
7080 |             })
7081 |         ));
7082 | 
7083 |         fetchState(true);
7084 |         fetchFileList();
7085 |         if (rollbackTarget) setTimeout(() => bundleAndPreview(null), 1000);
7086 |     }
