5174 |     function timeAgo(dateString) {
5175 |         const date = new Date(dateString);
5176 |         const now = new Date();
5177 |         const seconds = Math.floor((now - date) / 1000);
5178 |         if (seconds < 10) return 'just now';
5179 |         if (seconds < 60) return seconds + 's ago';
5180 |         const minutes = Math.floor(seconds / 60);
5181 |         if (minutes < 60) return minutes + 'm ago';
5182 |         const hours = Math.floor(minutes / 60);
5183 |         if (hours < 24) return hours + 'h ago';
5184 |         return date.toLocaleDateString();
5185 |     }
