7863 |     function extractTableNames(sql) {
7864 |         if (!sql) return [];
7865 |         const tables = [];
7866 |         const systemNoise = ['columns', 'tables', 'schemata', 'information_schema'];
7867 |         
7868 |         // Pattern 1: Standard FROM/JOIN (handles schema.table and "table")
7869 |         const fromRegex = /(?:FROM|JOIN)\s+(?:(?:"?\w+"?\.)?"?(\w+)"?)/gi;
7870 |         // Pattern 2: Metadata queries (WHERE table_name = '...')
7871 |         const metaRegex = /table_name\s*=\s*'([^']+)'/gi;
7872 | 
7873 |         let match;
7874 |         while ((match = fromRegex.exec(sql)) !== null) {
7875 |             const name = match[1];
7876 |             if (name && !tables.includes(name) && !systemNoise.includes(name.toLowerCase())) {
7877 |                 tables.push(name);
7878 |             }
7879 |         }
7880 |         
7881 |         while ((match = metaRegex.exec(sql)) !== null) {
7882 |             const name = match[1];
7883 |             if (name && !tables.includes(name) && !systemNoise.includes(name.toLowerCase())) {
7884 |                 tables.push(name);
7885 |             }
7886 |         }
7887 | 
7888 |         return tables;
7889 |     }
7890 | 
7891 |     function convertToCSV(resultObj) {
7892 |         const data = resultObj.data || [];
7893 |         if (!data.length) return '';
7894 |         
7895 |         const tables = extractTableNames(resultObj.sql);
7896 |         const metaHeader = tables.length > 0 ? `# Source Tables: ${tables.join(', ')}\n# Export Date: ${new Date().toISOString()}\n` : '';
7897 | 
7898 |         const headers = Object.keys(data[0]);
7899 |         const rows = data.map(row => 
7900 |             headers.map(header => {
7901 |                 let cell = row[header] === null || row[header] === undefined ? '' : row[header];
7902 |                 if (typeof cell === 'object') cell = JSON.stringify(cell);
7903 |                 return '"' + String(cell).replace(/"/g, '""') + '"';
7904 |             }).join(',')
7905 |         );
7906 |         return metaHeader + [headers.join(','), ...rows].join('\n');
7907 |     }
