2002 |                 // 2. Fix literal newlines inside strings (replace with \n)
2003 |                 .replace(/(\n)/g, (match, p1, offset) => {
2004 |                     // Only replace if we are likely inside a quoted string
2005 |                     const before = jsonString.slice(0, offset);
2006 |                     const quoteCount = (before.match(/"/g) || []).length;
2007 |                     return (quoteCount % 2 === 1) ? "\\n" : "\n";
2008 |                 });
