4851 |                 const diff = now - ts;
4852 |                 if (f.time === 'hour' && diff > 3600000) return false;
4853 |                 if (f.time === 'today' && diff > 86400000) return false;
4854 |                 if (f.time === 'week' && diff > 604800000) return false;
4855 |             }
4856 | 
4857 |             // 2. File Filter
4858 |             if (f.files.length > 0) {
4859 |                 let touchedFiles = [];
4860 |                 if (tab === 'history') touchedFiles = (item.ops || []).map(o => o.file_path || '');
4861 |                 if (tab === 'patcher') {
4862 |                     // Patcher logic is handled by applyFiltersToPatcher, but we add safety here
4863 |                     touchedFiles = (item.results || []).map(r => r.file);
4864 |                 }
