4867 |                     touchedFiles = match ? (match.ops || []).map(o => o.file_path || '') : [];
4868 |                 }
4869 |                 // Filter out empty paths
4870 |                 touchedFiles = touchedFiles.filter(p => p !== '');
4871 |                 if (touchedFiles.length > 0 && !touchedFiles.some(tf => f.files.includes(tf))) return false;
