2253 |     // --- CLIENT SIDE PATCH ENGINE (Smart Line-Matcher) ---
2254 |     function applyLocalPatch(content, ops) {
2255 |         let lines = content.split('\n');
2256 |         let logs = [];
2257 |         let success = true;
2258 | 
2259 |         if (typeof ops === 'string') {
2260 |             try { ops = JSON.parse(ops); } catch(e) { return { content, success: false, logs: ["Invalid JSON"]}; }
2261 |         }
2262 | 
2263 |         ops.forEach(op => {
2264 |             if (op.action === 'comment') return;
2265 |             if (op.action === 'create_file') { lines = op.content.split('\n'); logs.push('Created file'); return; }
2266 |             
2267 |             if (op.action === 'replace_block') {
2268 |                 // Strategy 1: Exact String Match (Fastest)
2269 |                 const currentStr = lines.join('\n');
2270 |                 if (currentStr.includes(op.find_block)) {
2271 |                     lines = currentStr.replace(op.find_block, op.replace_with).split('\n');
2272 |                     logs.push('Exact match applied');
2273 |                     return;
2274 |                 }
2275 | 
2276 |                 // Strategy 2: Line-by-Line Fuzzy Match (Whitespace Agnostic)
2277 |                 const searchLines = op.find_block.split('\n').map(l => l.trim()).filter(l => l !== '');
2278 |                 if (searchLines.length === 0) return;
2279 | 
2280 |                 let matchStart = -1;
2281 |                 let matchEnd = -1;
2282 | 
2283 |                 // Scan file lines
2284 |                 for (let i = 0; i < lines.length; i++) {
2285 |                     // If first line matches (ignoring whitespace)
2286 |                     if (lines[i].trim() === searchLines[0]) {
2287 |                         // Check subsequent lines
2288 |                         let allMatch = true;
2289 |                         let fileOffset = 0;
2290 |                         let searchOffset = 1;
2291 |                         
2292 |                         while (searchOffset < searchLines.length) {
2293 |                             if (i + fileOffset + 1 >= lines.length) { allMatch = false; break; }
2294 |                             const nextFile = lines[i + fileOffset + 1].trim();
2295 |                             // Skip empty lines in file if they aren't in search block
2296 |                             if (nextFile === '') {
2297 |                                 fileOffset++;
2298 |                                 continue;
2299 |                             }
2300 |                             if (nextFile !== searchLines[searchOffset]) {
2301 |                                 allMatch = false;
2302 |                                 break;
2303 |                             }
2304 |                             fileOffset++;
2305 |                             searchOffset++;
2306 |                         }
2307 | 
2308 |                         if (allMatch) {
2309 |                             matchStart = i;
2310 |                             matchEnd = i + fileOffset;
2311 |                             break;
2312 |                         }
2313 |                     }
2314 |                 }
2315 | 
2316 |                 if (matchStart !== -1) {
2317 |                     // Replace the range of lines
2318 |                     const replacement = op.replace_with.split('\n');
2319 |                     lines.splice(matchStart, (matchEnd - matchStart) + 1, ...replacement);
2320 |                     logs.push(`Fuzzy match applied (Lines ${matchStart+1}-${matchEnd+1})`);
2321 |                 } else {
2322 |                     success = false;
2323 |                     logs.push(`Failed to find block: "${op.find_block.substring(0, 30)}..."`);
2324 |                     console.warn("Patch Mismatch. File has:", content.substring(0, 200), "... vs Search:", op.find_block);
2325 |                 }
2326 |             }
2327 |         });
2328 |         return { content: lines.join('\n'), success, logs };
2329 |     }
