5164 |     function formatBytes(bytes) {
5165 |         if (!bytes) return '0 B';
5166 |         const k = 1024;
5167 |         const sizes = ['B', 'KB', 'MB', 'GB'];
5168 |         const i = Math.floor(Math.log(bytes) / Math.log(k));
5169 |         return parseFloat((bytes / Math.pow(k, i)).toFixed(1)) + ' ' + sizes[i];
5170 |     }
