5172 |     function timeAgo(dateString) {
5173 |         const date = new Date(dateString);
5174 |         const now = new Date();
5175 |         const seconds = Math.floor((now - date) / 1000);
5176 |         if (seconds < 10) return 'just now';
5177 |         if (seconds < 60) return seconds + 's ago';
5178 |         const minutes = Math.floor(seconds / 60);
5179 |         if (minutes < 60) return minutes + 'm ago';
5180 |         const hours = Math.floor(minutes / 60);
5181 |         if (hours < 24) return hours + 'h ago';
5182 |         return date.toLocaleDateString();
5183 |     }
