5394 | 
5395 |         const attemptNavigation = async () => {
5396 |             const element = document.querySelector(selector);
5397 |             
5398 |             if (element) {
5399 |                 console.log("[DeepJump] Element found. Scrolling...");
5400 |                 
5401 |                 // Wait for any tab transition animations
5402 |                 await new Promise(r => setTimeout(r, 300));
5403 | 
5404 |                 let offsetTop = 0;
5405 |                 let curr = element;
5406 |                 while (curr && curr !== scrollContainer) {
5407 |                     offsetTop += curr.offsetTop;
