5409 |                 }
5410 | 
5411 |                 const targetScroll = offsetTop - (scrollContainer.clientHeight / 2) + (element.clientHeight / 2);
5412 |                 scrollContainer.scrollTo({ top: targetScroll, behavior: 'smooth' });
5413 | 
5414 |                 // Visual Highlight
