5425 |             }
5426 | 
5427 |             if (retryCount < MAX_RETRIES && loadMoreFn) {
5428 |                 console.log(`[DeepJump] Not found. Triggering loadMore (Attempt ${retryCount + 1})...`);
5429 |                 retryCount++;
5430 |                 showGlobalToast("ð Searching deeper...");
5431 |                 
5432 |                 await loadMoreFn(); 
5433 |                 await new Promise(r => setTimeout(r, 800)); // Wait for render
5434 |                 return attemptNavigation();
5435 |             }
5436 | 
5437 |             console.error("[DeepJump] Failed: Element not found after retries.");
5438 |             showGlobalToast("Entry not found in recent history.", true);
5439 |             console.groupEnd();
5440 |             return false;
5441 |         };
5442 | 
5443 |         setTimeout(attemptNavigation, 100);
