7035 |         if (!checkboxes.length) return;
7036 | 
7037 |         const idsToDelete = checkboxes.map(cb => cb.value);
7038 |         
7039 |         // Find the oldest record among the selection to determine rollback target
7040 |         // dbHistory is sorted newest -> oldest
7041 |         let oldestSelectedIndex = -1;
7042 |         checkboxes.forEach(cb => {
7043 |             const idx = dbHistory.findIndex(h => String(h.id) === String(cb.value));
7044 |             if (idx > oldestSelectedIndex) oldestSelectedIndex = idx;
7045 |         });
7046 | 
7047 |         // The target is the first record older than our selection that isn't also being deleted
7048 |         let rollbackTarget = null;
7049 |         for (let i = oldestSelectedIndex + 1; i < dbHistory.length; i++) {
7050 |             if (!idsToDelete.includes(String(dbHistory[i].id))) {
7051 |                 rollbackTarget = dbHistory[i];
7052 |                 break;
7053 |             }
