7861 |     function extractTableNames(sql) {
7862 |         if (!sql) return [];
7863 |         const tables = [];
7864 |         const systemNoise = ['columns', 'tables', 'schemata', 'information_schema'];
7865 |         
7866 |         // Pattern 1: Standard FROM/JOIN (handles schema.table and "table")
7867 |         const fromRegex = /(?:FROM|JOIN)\s+(?:(?:"?\w+"?\.)?"?(\w+)"?)/gi;
7868 |         // Pattern 2: Metadata queries (WHERE table_name = '...')
7869 |         const metaRegex = /table_name\s*=\s*'([^']+)'/gi;
7870 | 
7871 |         let match;
7872 |         while ((match = fromRegex.exec(sql)) !== null) {
7873 |             const name = match[1];
7874 |             if (name && !tables.includes(name) && !systemNoise.includes(name.toLowerCase())) {
7875 |                 tables.push(name);
7876 |             }
7877 |         }
7878 |         
7879 |         while ((match = metaRegex.exec(sql)) !== null) {
7880 |             const name = match[1];
7881 |             if (name && !tables.includes(name) && !systemNoise.includes(name.toLowerCase())) {
7882 |                 tables.push(name);
7883 |             }
7884 |         }
7885 | 
7886 |         return tables;
7887 |     }
7888 | 
7889 |     function convertToCSV(resultObj) {
7890 |         const data = resultObj.data || [];
7891 |         if (!data.length) return '';
7892 |         
7893 |         const tables = extractTableNames(resultObj.sql);
7894 |         const metaHeader = tables.length > 0 ? `# Source Tables: ${tables.join(', ')}\n# Export Date: ${new Date().toISOString()}\n` : '';
7895 | 
7896 |         const headers = Object.keys(data[0]);
7897 |         const rows = data.map(row => 
7898 |             headers.map(header => {
7899 |                 let cell = row[header] === null || row[header] === undefined ? '' : row[header];
7900 |                 if (typeof cell === 'object') cell = JSON.stringify(cell);
7901 |                 return '"' + String(cell).replace(/"/g, '""') + '"';
7902 |             }).join(',')
7903 |         );
7904 |         return metaHeader + [headers.join(','), ...rows].join('\n');
7905 |     }
