 879 | // Helper: Finds code block ignoring whitespace, tabs, newlines, and quote styles
 880 | function findBlockRobust(originalContent: string, searchBlock: string): { start: number; end: number } | null {
 881 |   if (!searchBlock || !originalContent) return null;
 882 | 
 883 |   const createFingerprint = (str: string) => {
 884 |     let clean = "";
 885 |     const map: number[] = [];
 886 |     for (let i = 0; i < str.length; i++) {
 887 |       if (!/\s/.test(str[i])) {
 888 |         clean += str[i];
 889 |         map.push(i);
 890 |       }
 891 |     }
 892 |     return { clean, map };
 893 |   };
 894 | 
 895 |   const fileFP = createFingerprint(originalContent);
 896 |   const searchFP = createFingerprint(searchBlock);
 897 | 
 898 |   // 1. Strict Structural Match
 899 |   let matchIndex = fileFP.clean.indexOf(searchFP.clean);
 900 | 
 901 |   // 2. Quote-Agnostic Fallback (e.g. " vs ')
 902 |   if (matchIndex === -1) {
 903 |     const normalizeQuotes = (s: string) => s.replace(/['"`]/g, '"');
 904 |     matchIndex = normalizeQuotes(fileFP.clean).indexOf(normalizeQuotes(searchFP.clean));
 905 |   }
 906 | 
 907 |   if (matchIndex === -1) return null;
 908 | 
 909 |   const start = fileFP.map[matchIndex];
 910 |   const end = fileFP.map[matchIndex + searchFP.clean.length - 1] + 1;
 911 |   return { start, end };
 912 | }
