 917 |   // Helper to find line by trimmed content
 918 |   const getLineIndex = (anchor: string) => {
 919 |       const cleanAnchor = anchor.trim();
 920 |       return lines.findIndex(l => l.trim() === cleanAnchor);
 921 |   };
