 923 |   try {
 924 |     // --- AI HEALING ---
 925 |     if (op.is_ai_fix) {
 926 |         if (op.ai_strategy === "range_replace" && op.start_line && op.end_line) {
 927 |             lines.splice(op.start_line - 1, (op.end_line - op.start_line) + 1, op.replace_with || op.content || "");
 928 |                         const shortMsg = op.explanation ? (op.explanation.substring(0, 150) + "...") : "AI Fixed";
