 974 |         }
 975 |         
 976 |         // Strategy C: Robust Block Anchor
 977 |         const match = findBlockRobust(content, op.anchor);
 978 |         if (match) {
 979 |              const before = content.substring(0, match.end);
 980 |              const after = content.substring(match.end);
